import { pipe } from "fp-ts/function";
import * as R from "fp-ts/Reader";
import * as S from "fp-ts/State";

type Env = { readonly table: string };
type Clauses = ReadonlyArray<string>;

const addWhere = (clause: string): S.State<Clauses, void> => (s) => [undefined, [...s, clause]];

const builder: R.Reader<Env, S.State<Clauses, string>> = (env) =>
  pipe(
    addWhere("deleted = false"),
    S.chain(() => addWhere("active = true")),
    S.map(() => env.table),
  );

const run = (env: Env) => {
  const [table, clauses] = builder(env)([]);
  return `SELECT * FROM ${table} WHERE ${clauses.join(" AND ")}`;
};

export const sql = run({ table: "users" });
