class DecodeError extends Data.TaggedError("DecodeError")<{ readonly why: string }> {}

const decodeJson = (b: string) =>
  Effect.try({ try: () => JSON.parse(b) as unknown, catch: () => new DecodeError({ why: "json" }) });
const decodeText = (b: string): Effect.Effect<string, DecodeError> => Effect.succeed(b);
const decodeProto = (b: Uint8Array): Effect.Effect<unknown, DecodeError> =>
  b.length > 0 ? Effect.succeed({ bytes: b.length }) : Effect.fail(new DecodeError({ why: "empty" }));

export const dispatch = (ct: string, body: string | Uint8Array) =>
  pipe(
    Match.value(ct),
    Match.when("application/json", () => decodeJson(String(body))),
    Match.when("text/plain", () => decodeText(String(body))),
    Match.when("application/protobuf", () => decodeProto(body as Uint8Array)),
    Match.orElse(() => Effect.fail(new DecodeError({ why: `unknown:${ct}` }))),
  );
