    Match.value(cmd),
    Match.tag("Add", ({ item }) => Ref.update(state, (s) => new Set([...s, item])).pipe(Effect.flatMap(() => Ref.get(state)), Effect.map((s) => [...s]))),
    Match.tag("Remove", ({ item }) => Ref.update(state, (s) => { const n = new Set(s); n.delete(item); return n }).pipe(Effect.flatMap(() => Ref.get(state)), Effect.map((s) => [...s]))),
    Match.tag("List", () => Ref.get(state).pipe(Effect.map((s) => [...s]))),
    Match.exhaustive,
  );

export const demo = Effect.gen(function* () {
  const state = yield* Ref.make<ReadonlySet<string>>(new Set());
  return yield* run(state)({ _tag: "Add", item: "a" });
});
