import { Effect, Match, Data, pipe } from "effect";

class DecodeError extends Data.TaggedError("DecodeError")<{ readonly ct: string }> {}

type Parsed = { readonly kind: string; readonly size: number };

const fromJson = (b: string): Effect.Effect<Parsed, DecodeError> =>
  Effect.try({ try: () => ({ kind: "json", size: JSON.parse(b) ? 1 : 0 }), catch: () => new DecodeError({ ct: "json" }) });
const fromCsv = (b: string): Effect.Effect<Parsed, DecodeError> =>
  Effect.succeed({ kind: "csv", size: b.split("\n").length });
const fromText = (b: string): Effect.Effect<Parsed, DecodeError> => Effect.succeed({ kind: "text", size: b.length });

const decorate = (p: Parsed): Effect.Effect<Parsed> =>
  Effect.succeed({ ...p, size: p.size + 1 });

export const route = (ct: string, body: string) =>
  pipe(
    Match.value(ct),
    Match.when("application/json", () => fromJson(body)),
    Match.when("text/csv", () => fromCsv(body)),
    Match.when("text/plain", () => fromText(body)),
    Match.orElse((c) => Effect.fail(new DecodeError({ ct: c }))),
    Effect.flatMap(decorate),
  );
